#!/usr/bin/env bash
# ppac-pdk-doe-spc.sh — 新节点 / 新工艺导入（PPAC 定义 → 工艺整合+PDK → 单元工艺 DOE → 量测 SPC → 良率爬坡 → 量产移交） SOP walkthrough for 半导体芯片制造工艺.
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="半导体芯片制造工艺"
WORKFLOW="新节点 / 新工艺导入（PPAC 定义 → 工艺整合+PDK → 单元工艺 DOE → 量测 SPC → 良率爬坡 → 量产移交）"

usage() {
  cat <<EOF
ppac-pdk-doe-spc.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./ppac-pdk-doe-spc.sh             # interactive
  ./ppac-pdk-doe-spc.sh --dry-run
  ./ppac-pdk-doe-spc.sh --json
  ./ppac-pdk-doe-spc.sh --explain
  ./ppac-pdk-doe-spc.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "新节点 / 新工艺导入（PPAC 定义 → 工艺整合+PDK → 单元工艺 DOE → 量测 SPC → 良率爬坡 → 量产移交）" 工作流。

一句话: 从「一个新技术节点立项（如 N2、A16）或客户新产品工艺要求」到「一个可量产、有 PDK、良率达标、已移交量产的工艺平台」。这是 fab 工艺工程的总流程，套住其余所有子 workflow。 (evidence: [T03-S004, T03-S005])

入门 SOP 共 6 步, 失败模式自检 4 项。

相关心智模型:
  • 物理硬约束 ⇄ 良率/成本经济约束（第一性双重张力）: 半导体工艺的每个决策都同时受两类硬约束——物理/化学/材料（量子隧穿、短沟道效应、RC 延迟、热预算、缺陷物理）与良率/成本经济（D0 缺陷密度、每片晶圆成本、wph、折旧）；摩尔定律首先是**经济命
  • 设备/工艺是必要非充分，良率 know-how 才是真壁垒: 能不能做先进制程，从来不是「有没有 EUV/光刻机」单一决定的——设备 + 材料 + 刻蚀/沉积 + 工艺整合 + 良率爬坡**五要素缺一不可**，而良率 ramp 的 know-how 是 silo

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**器件目标与 PPAC 定义**：定义节点的 Power/Performance/Area/Cost 目标与器件架构（FinFET→GAA nanosheet→CFET），用 IRDS 路线图与 TCAD 先评估可行性。 (evidence: [T03-S004, T04-S007])"
  "**工艺整合方案 + 早期 PDK**：把目标拆成 FEOL/MOL/BEOL 模块，定整合流程与模块间 trade-off，用 SEMulator3D/TCAD 先在电脑里验证整合，产出早期设计规则与 PDK。 (evidence: [T03-S004, T02-S006, T02-S008])"
  "**单元工艺开发（DOE 找窗口）**：对每个关键单元工艺（光刻/刻蚀/沉积/CMP/注入）跑 DOE 开发配方（= workflow 2）。 (evidence: [T04-S034])"
  "**量测建立 + SPC**：为每个工艺建量测方法（CD-SEM/OCD/overlay）与 SPC 控制限。 (evidence: [T02-S019])"
  "**良率爬坡**：流片测试结构与产品，做缺陷分类→commonality→根因→改善（= workflow 3）。 (evidence: [T03-S001])"
  "**量产移交（copy-exactly）**：把锁定工艺与 PDK 移交 HVM fab，严格复制（= workflow 6），客户拿 PDK 设计流片。 (evidence: [T03-S007])"
)
declare -a FAILURE_MODES=(
  "**单元工艺各自最优、整合却失败**：每个 unit process 调到最好但模块间 trade-off 冲突（如热预算 vs 掺杂剖面），整合不起来 —— 必须 step2 用 SEMulator3D/TCAD 先验整合，DTCO 协同。"
  "**PDK 给得太晚**：客户拿不到稳定 PDK 无法设计，节点空转 —— PDK 与工艺开发并行（DTCO design enablement 阶段）。"
  "**「买齐设备就能导入节点」**：EUV/设备只是必要非充分，材料+整合+良率 know-how 缺一不可，国产替代叙事尤其须诚实拆穿 —— 五要素（设备+材料+工艺+整合+良率）齐备才算能导入。 (evidence: [T01-S017])"
  "**研发线良率好、HVM 塌方**：没严格 copy-exactly，HVM 设备指纹与研发线不同 —— step6 严格复制 + 设备指纹比对。"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "ppac-pdk-doe-spc-walkthrough"
fi
